const BASE = (process.env.OM_BASE_URL || 'http://localhost:8888').replace(/\/$/, '') + '/api/v3/openmeter';
const KEY = process.env.OM_API_KEY || '';
const HDRS = { 'Content-Type': 'application/json', ...(KEY ? { 'Authorization': `Bearer ${KEY}` } : {}) };
const sfx = `${Date.now()}_${Math.floor(Math.random() * 9999)}`;

async function api(method, path, body) {
  const resp = await fetch(`${BASE}${path}`, {
    method,
    headers: HDRS,
    ...(body !== undefined ? { body: JSON.stringify(body) } : {})
  });
  let json = null;
  try { json = await resp.json(); } catch (_) {}
  return { status: resp.status, json };
}

// 1. Create
let r = await api('POST', '/addons', {
  key: `lifecycle_addon_${sfx}`,
  name: `Lifecycle Addon ${sfx}`,
  currency: 'USD',
  instance_type: 'single',
  rate_cards: [{
    key: `addon_fee_${sfx}`,
    name: 'Addon Fee',
    billing_cadence: 'P1M',
    payment_term: 'in_advance',
    price: { type: 'flat', amount: '10' }
  }]
});
expect(r.status, '1. Create → 201').to.equal(201);
expect(r.json.status, '1. Create → status is draft').to.equal('draft');
expect(r.json.version, '1. Create → version is 1').to.equal(1);
expect(r.json.effective_from, '1. Create → effective_from is null').to.not.be.ok;
const addonId = r.json.id;
const rcKey = `addon_fee_${sfx}`;

// 2. Get
r = await api('GET', `/addons/${addonId}`);
expect(r.status, '2. Get → 200').to.equal(200);
expect(r.json.id, '2. Get → id matches').to.equal(addonId);
expect(r.json.status, '2. Get → status is draft').to.equal('draft');

// 3. List
r = await api('GET', '/addons?page[size]=1000');
expect(r.status, '3. List → 200').to.equal(200);
const found3 = (r.json.data || []).some(a => a.id === addonId);
expect(found3, '3. List → contains created addon').to.be.true;

// 4. Update
r = await api('PUT', `/addons/${addonId}`, {
  name: 'Lifecycle Addon Updated',
  instance_type: 'single',
  rate_cards: [{
    key: rcKey,
    name: 'Addon Fee',
    billing_cadence: 'P1M',
    payment_term: 'in_advance',
    price: { type: 'flat', amount: '10' }
  }]
});
expect(r.status, '4. Update → 200').to.equal(200);
expect(r.json.name, '4. Update → name changed').to.equal('Lifecycle Addon Updated');
expect(r.json.status, '4. Update → still draft').to.equal('draft');

// 5. Publish
r = await api('POST', `/addons/${addonId}/publish`);
expect(r.status, '5. Publish → 200').to.equal(200);
expect(r.json.status, '5. Publish → status is active').to.equal('active');
expect(r.json.effective_from, '5. Publish → effective_from is set').to.be.ok;

// 6. Delete while active → rejected
r = await api('DELETE', `/addons/${addonId}`);
expect(r.status, '6. Delete active → 400').to.equal(400);

// 7. Archive
r = await api('POST', `/addons/${addonId}/archive`);
expect(r.status, '7. Archive → 200').to.equal(200);
expect(r.json.status, '7. Archive → status is archived').to.equal('archived');
expect(r.json.effective_to, '7. Archive → effective_to is set').to.be.ok;

// 8. Delete after archive
r = await api('DELETE', `/addons/${addonId}`);
expect(r.status, '8. Delete archived → 204').to.equal(204);

// 9. Get after delete
r = await api('GET', `/addons/${addonId}`);
expect(r.status, '9. Get deleted → 200').to.equal(200);
expect(r.json.deleted_at, '9. Get deleted → deleted_at is set').to.be.ok;

