async function createAddonWithStatus(sfx2, targetStatus) {
  let r = await api('POST', '/addons', { key: `matrix_addon_${sfx2}`, name: `Matrix Addon ${sfx2}`, currency: 'USD', instance_type: 'single', rate_cards: [{ key: `arc_${sfx2}`, name: 'Fee', billing_cadence: 'P1M', payment_term: 'in_advance', price: { type: 'flat', amount: '5' } }] });
  const id = r.json.id;
  if (targetStatus === 'active' || targetStatus === 'archived') {
    r = await api('POST', `/addons/${id}/publish`);
  }
  if (targetStatus === 'archived') {
    r = await api('POST', `/addons/${id}/archive`);
  }
  return { id, status: targetStatus };
}

async function createPlanWithStatus(sfx2, targetStatus) {
  let r = await api('POST', '/plans', { key: `matrix_plan_${sfx2}`, name: `Matrix Plan ${sfx2}`, currency: 'USD', billing_cadence: 'P1M', phases: [{ key: `ph_${sfx2}`, name: 'Phase', rate_cards: [{ key: `rc_${sfx2}`, name: 'Fee', billing_cadence: 'P1M', payment_term: 'in_advance', price: { type: 'flat', amount: '10' } }] }] });
  const plan = r.json;
  if (targetStatus === 'active' || targetStatus === 'archived') {
    r = await api('POST', `/plans/${plan.id}/publish`);
  }
  if (targetStatus === 'archived') {
    r = await api('POST', `/plans/${plan.id}/archive`);
  }
  return plan;
}

